<template>
  <v-select
    :value="value"
    :items="items"
    :item-title="itemText"
    :item-value="itemValue"
    return-object
    class="font-weight-black"
    :label="label"
    :disabled="disabled"
    color="#624fc6"
    variant="outlined"
    rounded
    clearable
    lazy-rules
    @update:model-value="$emit('update-value', $event)"
    :hint="hint"
    persistent-hint
    :rules="rules"
    hide-details="auto"
  ></v-select>
</template>
<script setup>
defineEmits(["update-value"]);

defineProps({
  value: {
    type: [Object, Number],
    default: null,
  },
  label: {
    type: String,
    default: "",
  },
  itemText: {
    type: [String],
    required: true,
  },
  itemValue: {
    type: [String, Number],
    required: true,
  },
  items: {
    type: Array,
    required: true,
  },
  rules: {
    type: Array,
    default: () => [],
  },
  hint: {
    type: String,
    default: "",
  },
  disabled: {
    type: Boolean,
    default: false,
  },
});
</script>
