<template>
  <v-container class="login" fluid>
    <v-row class="justify-center">
      <v-col cols="12">
        <v-form ref="form">
          <v-card class="card" width="1200">
            <v-row class="justify-center">
              <v-col
                cols="12"
                sm="12"
                md="5"
                lg="5"
                class="justify-center order-lg-2 order-md-2 order-sm-2 order-2"
              >
                <v-card-title class="d-flex justify-center mt-6 mb-3">
                  <h2>تسجيل الدخول</h2>
                </v-card-title>
                <v-card-text class="mt-2">
                  <Input
                    v-model="email"
                    autocomplete="email"
                    type="text"
                    label="البريد الألكتروني"
                    :rules="EmailRules"
                  />

                  <v-text-field
                    color="#624fc6"
                    v-model="password"
                    variant="outlined"
                    rounded
                    clearable
                    class="font-weight-black pt-5"
                    :type="showPassword ? 'text' : 'password'"
                    label="كلمة المرور"
                    autocomplete="current-password"
                    :append-inner-icon="
                      showPassword ? 'mdi-eye' : 'mdi-eye-off'
                    "
                    @click:append-inner="showPassword = !showPassword"
                    :rules="PasswordsRules"
                  />
                </v-card-text>
                <!-- <h4 @click="forgot_password" class="link-h4 mt-n6 mr-8">
                  هل نسيت كلمة مرور ؟
                </h4> -->

                <v-card-actions>
                  <v-btn
                    @click="login"
                    :loading="loading_login"
                    color="#624fc6"
                    variant="flat"
                    size="large"
                    class="px-16 mx-auto border-btn"
                    elevation="4"
                  >
                    <h4 style="color: white; font-size: 17px">تسجيل الدخول</h4>
                    <template v-slot:loader>
                      <span class="custom-loader">
                        <v-icon color="white">mdi-cached</v-icon>
                      </span>
                    </template>
                  </v-btn>
                </v-card-actions>
                <!-- <v-card-actions>
                  <h4 class="link-h4 mr-8" @click="redirect">ليس لديه حساب</h4>
                </v-card-actions> -->
              </v-col>
              <v-col
                cols="12"
                sm="12"
                md="7"
                lg="7"
                class="d-flex justify-center pa-0 ma-0 order-lg-2 order-md-2 order-sm-1 order-1"
              >
                <v-img class="img" src="../assets/login.jpg" height="500">
                </v-img>
              </v-col>
            </v-row>
          </v-card>
        </v-form>
      </v-col>
    </v-row>
  </v-container>
</template>

<script setup>
import { ref, computed } from "vue";
import { useRouter } from "vue-router";
import { useUserStore } from "@/stores/user";
import Input from "../components/layout/Input.vue";

const email = ref(null);
const password = ref(null);
const showPassword = ref(false);
const form = ref(null);

const EmailRules = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 7 || "الحد الادنى لعدد الاحرف هوه 7",
  (value) => {
    const pattern =
      /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/;
    return pattern.test(value) || "ادخلت رموز غير صحيحه";
  },
];

const PasswordsRules = [
  (value) => !!value || "هذا الحقل مطلوب",
  (value) => (value || "").length >= 8 || "الحد الادنى لعدد الاحرف هوه 8",
];

const userStore = useUserStore();
const router = useRouter();

const loading_login = computed(() => userStore.loading_login);

const login = async () => {
  if (form.value.validate()) {
    try {
      await userStore.login({
        email: email.value,
        password: password.value,
      });
      router.push({ name: "home" }); // redirect after login success
      // eslint-disable-next-line no-unused-vars
    } catch (e) {
      // error already handled in store
    }
  }
};


</script>
<style scoped>
.card {
  width: 100%;
  margin-top: 60px !important;
  margin: auto;
  border-radius: 15px;
  font-family: "Cairo", sans-serif;
  box-shadow: 0px 0px !important;
}
.login {
  /* opacity: 80%; */
  height: 100%;
}
.img {
  width: 100%;
  border-radius: 15px;
}
.card-img {
  background: rgba(255, 255, 255, 0);
  border-radius: 16px;
  box-shadow: 0 4px 30px rgba(0, 0, 0, 0.1);
  backdrop-filter: blur(8.7px);
  -webkit-backdrop-filter: blur(8.7px);
  /* border: 0.1px solid rgb(26, 95, 122); */
  box-shadow: rgba(0, 0, 0, 0.05) 0px 0px 0px 1px;
  margin-top: 100px;
}
.link-h4 {
  cursor: pointer;
}
.link-h4:hover {
  text-decoration: underline;
  color: darkblue;
}
</style>
